			timeWindowTightness = 1.0 / float64(oris[j].TimeEnd-oris[j].TimeStart+1)
		}
		penaltyMul = 1.0 + timeWindowTightness*compactnessFactor
		for i := 0; i < dispatch.AssignsLen; i++ {
			oldCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(id, oris[j], dess[j])
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 && newCost >= oldCost-1e-9 {
					rawDelta := newCost - oldCost
					score := rawDelta + penaltyBase*penaltyMul*(float64(i%8)/10.0)
					feasible = append(feasible, cand{i, score, 0})
				}
				dispatch.Assigns[i].RemoveShip(id)
				dispatch.Assigns[i].GenRoute()
				dispatch.Assigns[i].Cost = oldCost
			}
		}
		if len(feasible) > 1 {
			for k := 0; k < len(feasible); k++ {
				secondBest := 1e18
				for m := 0; m < len(feasible); m++ {
